local count = 0
for path, b64 in pairs(files) do
  local dir = path:match("^(.*)/[^/]*$")
  if dir and not fs.exists(dir) then
    fs.makeDir(dir)
  end
  local f = fs.open(path, "w")
  f.write(decode(b64))
  f.close()
  count = count + 1
  term.setTextColor(colors.lightGray)
  print("  [" .. count .. "] " .. path)
end

term.setTextColor(colors.green)
print("")
print("Done! " .. count .. " files installed.")
term.setTextColor(colors.white)
print("Reboot to start CraftDroid.")
